// n8n Code node (plain JS)
// Input Normalizer — minimal & maintainable
// Assumes Spark form emits booleans, numbers, and enums you control.

function val(v, def) {
  return (v === undefined || v === null || v === "") ? def : v;
}

function num(v, def) {
  if (typeof v === "number" && Number.isFinite(v)) return v;
  const n = Number(v);
  return Number.isFinite(n) ? n : def;
}

function bool(v, def) {
  if (typeof v === "boolean") return v;
  if (v === "true") return true;
  if (v === "false") return false;
  return def;
}

function pickLength(v, def) {
  const s = String(val(v, def)).toLowerCase().trim();
  return (s === "short" || s === "medium" || s === "long") ? s : def;
}

const items = $input.all();

for (const item of items) {
  const src = item.json || {};

  item.json = {
    // Optional receipt/debug payload
    raw: src,

    notifier_email: val(src.notifier_email, ""),
    story_seed: val(src.story_seed, ""),
    project_mode: val(src.project_mode, "blog_post"),
    target_brand: val(src.target_brand, "tonka_blog"),
    target_audience: val(src.target_audience, ""),

    sliders: {
      fact_to_fiction: num(src.fact_to_fiction, 50),
      creativity_to_reporter: num(src.creativity_to_reporter, 50),
      tone_strictness: num(src.tone_strictness, 50),
    },

    draft: {
      length: pickLength(src.draft_length, "short"),
    },

    research: {
      enable_research: bool(src.enable_research, false),
      facts: val(src.facts, null),
    },

    outputs: {
      blog_post: bool(src.output_blog_post, true),
      reference_doc: bool(src.output_reference_doc, false),
      future_story_arc: bool(src.output_future_story_arc, false),
      visual_prompts: bool(src.output_visual_prompts, false),
      gdocs_folder_id: val(src.gdocs_folder_id, null),
    },
  };
}

return items;

