  item.json.writer_panel = Object.entries(writers)
    .filter(([_, cfg]) => cfg && cfg.enabled)
    .map(([role, cfg]) => ({
      role,
      weight: typeof cfg.weight === 'number' ? cfg.weight : 0,
    }));
}

return items;

