const items = $input.all();

for (const item of items) {
  // OpenAI returns object directly, not string
  const payload = item.json.output?.[0]?.content?.[0]?.text ?? item.json;

  // If OpenAI returned an object, use it directly.
  // If it returned a string, parse it.
  const parsed =
    typeof payload === 'string'
      ? JSON.parse(payload)
      : payload;

  const role = parsed.role ?? 'action';
  const notes = Array.isArray(parsed.notes) ? parsed.notes : [];

  const weight =
    typeof parsed.weight === 'number'
      ? parsed.weight
      : (item.json.writers?.action?.weight ?? 0);

  item.json.writer_note = {
    role,
    notes,
    weight,
  };
}

return items;

