const writerPanel = [];
/** @type {Record<string, { role: string; notes: any[]; weight: number }>} */
const byRole = {};

for (const item of items) {
  const note = item.json.writer_note;

  if (!note || !Array.isArray(note.notes)) continue;

  const entry = {
