// Normalize Draft Context
// Input: multiple items (writer notes, research, base context)
// Output: single clean item for Head Writer / Switch Target Brand / Apply Project Mode Profile

const items = $input.all();

// 1) Identify the "base" context item (story_seed + project etc.)
const baseItem =
  items.find((i) => i.json && i.json.story_seed) ||
  items[items.length - 1];

/** @type {any} */
const base = (baseItem && baseItem.json) ? baseItem.json : {};

// 2) Merge writer notes from any writer_panel / writers_by_role

/**
 * @typedef {Object} WriterNote
 * @property {string} role
 * @property {string[]} notes
 * @property {number|undefined} weight
 */

/** @type {Record<string, WriterNote>} */
const writerNotes = {};

/**
 * @param {string} role
 * @param {string[]} notes
 * @param {number|undefined} weight
 */
function addNotes(role, notes, weight) {
  const validRole = typeof role === 'string' && role.trim().length > 0;
  const validNotes = Array.isArray(notes) && notes.length > 0;

  if (validRole && validNotes) {
    if (!writerNotes[role]) {
      writerNotes[role] = {
        role,
        notes: [],
        weight: undefined,
      };
    }

    writerNotes[role].notes.push(...notes);

    if (typeof weight === 'number') {
      writerNotes[role].weight = weight;
    }
  }
}

// Walk all items to collect notes from any panel or by_role
for (const item of items) {
  /** @type {any} */
  const j = item.json || {};

  // writer_panel style: [{ role, notes?, weight }]
  if (Array.isArray(j.writer_panel)) {
    for (const wp of j.writer_panel) {
      if (!wp || !wp.role) continue;
      addNotes(
        String(wp.role),
        Array.isArray(wp.notes) ? wp.notes : [],
        typeof wp.weight === 'number' ? wp.weight : undefined
      );
    }
  }

  // writers_by_role style: { action: { role, notes, weight }, ... }
  if (j.writers_by_role && typeof j.writers_by_role === 'object') {
    for (const roleKey of Object.keys(j.writers_by_role)) {
      const wr = j.writers_by_role[roleKey];
      if (!wr) continue;
      addNotes(
        String(wr.role || roleKey),
        Array.isArray(wr.notes) ? wr.notes : [],
        typeof wr.weight === 'number' ? wr.weight : undefined
      );
    }
  }
}

// Backfill missing writerNotes weights from base.writers
/** @type {any} */
const baseWriters = base.writers || {};

for (const role of Object.keys(writerNotes)) {
  const noteObj = writerNotes[role];
  if (typeof noteObj.weight !== 'number') {
    const w = baseWriters[role] && typeof baseWriters[role].weight === 'number'
      ? baseWriters[role].weight
      : 0;
    noteObj.weight = w;
  }
}

// 2b) De-duplicate notes per writer (defensive clean-up)
for (const role of Object.keys(writerNotes)) {
  const wn = writerNotes[role];
  if (Array.isArray(wn.notes)) {
    wn.notes = Array.from(new Set(wn.notes));
  }
}

// 3) Unify research config (enable_research + facts) and research results (findings + sources + citations)

/** @type {{ enable_research?: boolean; facts?: string }} */
let researchConfig = {};

/** @type {{ role?: string; findings?: string[]; sources?: string[]; weight?: number }} */
let researchResult = {};

/** @type {string[]} */
let citations = [];

for (const item of items) {
  /** @type {any} */
  const j = item.json || {};

  // config: research.enable_research / research.facts
  if (j.research && Object.prototype.hasOwnProperty.call(j.research, 'enable_research')) {
    researchConfig = j.research;
  }

  // result: research.findings / research.sources / research.weight
  if (j.research && Array.isArray(j.research.findings)) {
    researchResult = j.research;
  }

  // citations from Perplexity
  if (Array.isArray(j.citations) && j.citations.length > 0) {
    citations = j.citations;
  }
}

// Build unified research object
const unifiedResearch = {
  enable_research:
    typeof researchConfig.enable_research === 'boolean'
      ? researchConfig.enable_research
      : false,
  facts:
    typeof researchConfig.facts === 'string'
      ? researchConfig.facts
      : '',
  role: researchResult.role || 'researcher',
  findings: Array.isArray(researchResult.findings)
    ? researchResult.findings
    : [],
  sources: Array.isArray(researchResult.sources)
    ? researchResult.sources
    : [],
  weight:
    typeof researchResult.weight === 'number'
      ? researchResult.weight
      : (
        baseWriters.documentary && typeof baseWriters.documentary.weight === 'number'
          ? baseWriters.documentary.weight
          : 0
      ),
  citations,
};

// 4) Build a clean, final context object for the Head Writer

/** @type {any} */
const project = base.project || {};

const final = {
  // core narrative seed
  story_seed: base.story_seed || '',

  // project identity (normalized)
  project: {
    mode: project.mode || base.project_mode || null,
    brand: project.brand || base.target_brand || null,
    audience: project.audience || base.target_audience || null,
  },

  project_mode: project.mode || base.project_mode || null,
  target_brand: project.brand || base.target_brand || null,
  target_audience: project.audience || base.target_audience || null,

  // sliders / meta
  creative: base.creative || {},
  revision: base.revision || {},
  outputs: base.outputs || {},
  tokens: base.tokens || {},

  // writer weighting metadata from Genre Tone Router
  writers: baseWriters,

  // writer panel = role + weight only (no notes)
  writer_panel: Array.isArray(base.writer_panel)
    ? base.writer_panel.map((wp) => ({
        role: wp.role,
        weight: typeof wp.weight === 'number' ? wp.weight : 0,
      }))
    : [],

  // merged brainstorm notes, keyed by role
  writer_notes: writerNotes,

  // unified research substrate
  research: unifiedResearch,
};

// 5) Return a single clean item
return [
  {
    json: final,
  },
];

