    .replace(/^\s*```[a-zA-Z]*\s*/m, '')
    // remove any trailing ``` at end
    .replace(/```$/m, '')
    // remove any remaining ``` blocks inside
    .replace(/```[a-zA-Z]*\s*/g, '')
