const allowed = ["hero", "detail", "process", "environment", "metaphor"];

function asArray(v) {
  return Array.isArray(v) ? v : [];
}

function clean(s) {
  return String(s ?? "").replace(/[ \t]{2,}/g, " ").trim();
}

// n8n Code node: get all incoming items via $input
const inItems = $input.all();

return inItems.map((it) => {
  const j = it.json;

  // Primary: OpenAI wrapper shape you've shown
  let vp =
    j?.output?.[0]?.content?.[0]?.text?.visual_prompts ??
    j?.visual_prompts ??
    [];

  vp = asArray(vp)
    .map((p) => ({
      intent: clean(p?.intent).toLowerCase(),
      prompt: clean(p?.prompt),
    }))
    .filter((p) => allowed.includes(p.intent) && p.prompt);

  // Deduplicate intents
  const seen = new Set();
  vp = vp.filter((p) => (seen.has(p.intent) ? false : (seen.add(p.intent), true)));

  // Order + cap
  vp.sort((a, b) => allowed.indexOf(a.intent) - allowed.indexOf(b.intent));
  vp = vp.slice(0, 5);

  // Deterministic IDs
  const finalPrompts = vp.map((p, i) => ({
    id: `vp-${String(i + 1).padStart(2, "0")}`,
    intent: p.intent,
    prompt: p.prompt,
  }));

  const { output, ...rest } = j;

  return {
    json: {
      ...rest,
      visual_prompts: finalPrompts,
    },
  };
});

